import { Component } from '@angular/core';
import { Form, FormGroup, FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';

@Component({
  selector: 'app-signup',
  imports: [ReactiveFormsModule],
  templateUrl: './signup.html',
  styleUrls: ['./signup.css'],
  standalone: true
})
export class Signup {

  private signupForm: FormGroup;
  constructor(private readonly formBuilder: FormBuilder) {

    this.signupForm = this.formBuilder.group({
      customerName: ['', Validators.required],
      customerNumber: ['', Validators.required]
    });

  }

  submitForm() {
    console.log("signup...");
  }
}
<div class="card shadow-sm">
  <div class="card-header bg-lightly py-3">
    <h3 class="card-title">
      Register User
    </h3>
  </div>

  <div class="card-body p-4">
    <form [formGroup]="signupForm" (ngSubmit)="submitForm()" class="py-2">

      <div class="form-group">
        <label for="email">Email</label>
        <input type="email" class="form-control" formControlName="email" placeholder="user@company.co.za">
      </div>

      <div class="form-group">
        <label for="password">Contact Number</label>
        <input type="password" class="form-control" formControlName="password" placeholder="Us3r0n3">
      </div>

      <div class="row form-group py-4">
        <button type="submit"
                class="btn btn-primary col-md-3"
                [disabled]="!customerForm.valid">
                Submit
        </button>

        <a class="nav-link px-2 link-secondary col-md-3 "
           [routerLink]="['/customer-list']">
                Cancel
        </a>
      </div>
    </form>
  </div>
</div>
